// Pega o texto da IA
let text = ($input.item.json.messages || $input.item.json.output || $input.item.json.text || "").toString();

// 1. MODO SILENCIOSO
if (text.includes("[SILENCIO]") || text.trim() === "") {
  return []; 
}

// 2. FILTRO DE ERRO DE LEITURA (A IA Vision falha, então assumimos sucesso manual)
if (text.includes("Não consegui ler") || text.includes("envie o PDF")) {
   // Força a mensagem de sucesso para acalmar o cliente
   text = "Recebi sua documentação e já anexei ao seu processo seguro. A equipe de auditoria vai analisar manualmente.";
}

// 3. SEPARADOR INTELIGENTE
// Se a mensagem for longa e não tiver "||" (Script de encerramento), mandamos como está.
// Se tiver "||", separamos.
let parts = text.includes("||") ? text.split("||") : [text];

// Limite de segurança: 4 balões
parts = parts.slice(0, 4);

const results = [];
const uniqueMessages = new Set(); 

for (const part of parts) {
  let cleanPart = part.trim();
  // Deduplicação: Se a frase for igual a anterior, ignora.
  if (cleanPart !== "" && !uniqueMessages.has(cleanPart)) {
    uniqueMessages.add(cleanPart);
    results.push({
      json: {
        message_part: cleanPart
      }
    });
  }
}

return results;

// Extrai tipo de mídia e URL do payload da Evolution API
const webhook = $('Webhook').item.json || {};
const data = webhook.body?.data || {};
const message = data.message || {};
const messageType = data.messageType || 'conversation';

let tipo_midia = 'texto';
let media_url = null;
let conteudo_texto = '';

switch (messageType) {
  case 'audioMessage':
    tipo_midia = 'audio';
    media_url = message.mediaUrl || message.audioMessage?.url || (message.base64 ? 'data:audio/ogg;base64,' + message.base64 : null);
    conteudo_texto = media_url;
    break;
  case 'imageMessage':
    tipo_midia = 'image';
    media_url = message.mediaUrl || message.imageMessage?.url || null;
    conteudo_texto = media_url || message.caption || '[Imagem]';
    break;
  case 'documentMessage':
  case 'documentWithCaptionMessage':
    tipo_midia = 'document';
    media_url = message.mediaUrl || message.documentMessage?.url || message.documentWithCaptionMessage?.message?.documentMessage?.url || null;
    const fileName = message.documentMessage?.fileName || message.documentWithCaptionMessage?.message?.documentMessage?.fileName || 'documento';
    conteudo_texto = media_url || '[Documento: ' + fileName + ']';
    break;
  case 'stickerMessage':
    tipo_midia = 'image';
    media_url = message.mediaUrl || message.stickerMessage?.url || null;
    conteudo_texto = media_url || '[Sticker]';
    break;
  case 'videoMessage':
    tipo_midia = 'image';
    media_url = message.mediaUrl || message.videoMessage?.url || null;
    conteudo_texto = media_url || '[Vídeo]';
    break;
  case 'conversation':
  default:
    tipo_midia = 'texto';
    conteudo_texto = message.conversation || message.extendedTextMessage?.text || '';
    break;
}

return [{
  json: {
    tipo_midia,
    media_url,
    conteudo_texto,
    messageType,
    whatsapp_id: data.key?.remoteJid || '',
    id_whatsapp: data.key?.id || '',
    fromMe: data.key?.fromMe || false
  }
}];
